/**
 * Minimal YAML parser using `js-yaml` bundled approach.
 * Since we can't guarantee npm packages in act containers,
 * we use a simple exec-based approach for the test harness.
 */

const YAML = {
  /**
   * Parse YAML string into a JavaScript object.
   * Uses bun's built-in capabilities or a simple regex-based approach
   * for the subset of YAML we need (GitHub Actions workflow files).
   */
  parse(input: string): any {
    // Use a child process to leverage Python's yaml parser if available,
    // or fall back to a simple line-based parser
    try {
      const { execSync } = require("child_process");
      // Use Python + json to parse YAML (Python has yaml in stdlib-adjacent)
      const result = execSync(
        `python3 -c "import yaml, json, sys; print(json.dumps(yaml.safe_load(sys.stdin.read())))"`,
        {
          input,
          encoding: "utf-8",
          stdio: ["pipe", "pipe", "pipe"],
        }
      );
      return JSON.parse(result);
    } catch {
      // Fallback: use a simple approach for basic structure checks
      return parseSimpleYaml(input);
    }
  },
};

/**
 * Very basic YAML parser for GitHub Actions workflow structure.
 * Only handles the subset needed for our structural tests.
 */
function parseSimpleYaml(input: string): any {
  const lines = input.split("\n");
  const result: any = {};
  let currentTopKey = "";
  let currentSecondKey = "";

  for (const line of lines) {
    const trimmed = line.trimEnd();
    if (trimmed === "" || trimmed.startsWith("#")) continue;

    const indent = line.length - line.trimStart().length;

    if (indent === 0 && trimmed.includes(":")) {
      const [key, ...rest] = trimmed.split(":");
      const value = rest.join(":").trim();
      currentTopKey = key.trim();
      if (value) {
        result[currentTopKey] = value;
      } else {
        result[currentTopKey] = {};
      }
      currentSecondKey = "";
    } else if (indent === 2 && trimmed.trim().includes(":")) {
      const t = trimmed.trim();
      const [key, ...rest] = t.split(":");
      const value = rest.join(":").trim();
      currentSecondKey = key.trim();
      if (value) {
        if (typeof result[currentTopKey] !== "object") result[currentTopKey] = {};
        result[currentTopKey][currentSecondKey] = value;
      } else {
        if (typeof result[currentTopKey] !== "object") result[currentTopKey] = {};
        result[currentTopKey][currentSecondKey] = {};
      }
    }
  }

  return result;
}

export default YAML;

