      return parseSimpleYaml(input);
    }
  },
};

/**
 * Very basic YAML parser for GitHub Actions workflow structure.
 * Only handles the subset needed for our structural tests.
 */
function parseSimpleYaml(input: string): any {
  const lines = input.split("\n");
  const result: any = {};
  let currentTopKey = "";
  let currentSecondKey = "";

  for (const line of lines) {
    const trimmed = line.trimEnd();
    if (trimmed === "" || trimmed.startsWith("#")) continue;

    const indent = line.length - line.trimStart().length;

    if (indent === 0 && trimmed.includes(":")) {
      const [key, ...rest] = trimmed.split(":");
      const value = rest.join(":").trim();
      currentTopKey = key.trim();
      if (value) {
        result[currentTopKey] = value;
      } else {
        result[currentTopKey] = {};
      }
      currentSecondKey = "";
    } else if (indent === 2 && trimmed.trim().includes(":")) {
      const t = trimmed.trim();
      const [key, ...rest] = t.split(":");
      const value = rest.join(":").trim();
      currentSecondKey = key.trim();
      if (value) {
        if (typeof result[currentTopKey] !== "object") result[currentTopKey] = {};
        result[currentTopKey][currentSecondKey] = value;
      } else {
        if (typeof result[currentTopKey] !== "object") result[currentTopKey] = {};
        result[currentTopKey][currentSecondKey] = {};
      }
    }
  }

  return result;
}

export default YAML;

